import React, { useState, useEffect } from "react";
import axios from "axios";

const ProjectPage = () => {
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    prerequisites: "",
    skills: "",
  });

  const [isFormVisible, setIsFormVisible] = useState(false);
  const [projects, setProjects] = useState([]);
  const [filters, setFilters] = useState({
    skill: "",
    level: "",
    duration: "",
    mode: "",
  });

  // Fetch projects from the backend
  useEffect(() => {
    axios
      .get("http://localhost:5000/projects")
      .then((response) => {
        setProjects(response.data);
      })
      .catch((error) => {
        console.error("Error fetching projects:", error);
      });
  }, []);

  // Handle form input changes
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Handle filter changes
  const handleFilterChange = (e) => {
    setFilters({ ...filters, [e.target.name]: e.target.value });
  };

  // Handle form submission to post a new project
  const handleSubmit = (e) => {
    e.preventDefault();
    axios
      .post("http://localhost:5000/projects", formData)
      .then((response) => {
        alert("Project posted successfully! 🎉");
        setFormData({ title: "", description: "", prerequisites: "", skills: "" });
        setIsFormVisible(false); // Hide form after submission
        setProjects([...projects, response.data]); // Add the new project to the list
      })
      .catch((error) => {
        console.error("Error posting project:", error);
      });
  };

  // Handle project connection submission (user fills out details to connect)
  const handleConnect = (projectId, userDetails) => {
    axios
      .post("http://localhost:5000/connect", { projectId, userDetails })
      .then((response) => {
        alert(response.data.message);
      })
      .catch((error) => {
        alert("Error connecting to project");
        console.error(error);
      });
  };

  // Filter projects based on user input
  const filteredProjects = projects.filter((project) => {
    return (
      (filters.skill ? project.skills.toLowerCase().includes(filters.skill.toLowerCase()) : true) &&
      (filters.level ? project.level === filters.level : true) &&
      (filters.duration ? project.duration === filters.duration : true) &&
      (filters.mode ? project.mode === filters.mode : true)
    );
  });

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center p-6">
      <div className="w-full max-w-3xl flex justify-between items-center bg-white p-4 rounded-lg shadow-md">
        <h2 className="text-xl font-bold text-gray-800">Projects</h2>
        <button
          onClick={() => setIsFormVisible(!isFormVisible)}
          className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
        >
          Post a Project 🚀
        </button>
      </div>

      {/* Filters */}
      <div className="w-full max-w-3xl mt-6 bg-white p-4 rounded-lg shadow-md">
        <h3 className="text-lg font-bold">Filter Projects</h3>
        <div className="grid grid-cols-2 gap-4">
          <input
            type="text"
            name="skill"
            value={filters.skill}
            onChange={handleFilterChange}
            className="w-full p-2 border rounded-lg"
            placeholder="Filter by Skill"
          />
          <select
            name="level"
            value={filters.level}
            onChange={handleFilterChange}
            className="w-full p-2 border rounded-lg"
          >
            <option value="">Select Level</option>
            <option value="Beginner">Beginner</option>
            <option value="Moderate">Moderate</option>
            <option value="Hard">Hard</option>
          </select>
          <select
            name="duration"
            value={filters.duration}
            onChange={handleFilterChange}
            className="w-full p-2 border rounded-lg"
          >
            <option value="">Select Duration</option>
            <option value="2 weeks">2 weeks</option>
            <option value="1 month">1 month</option>
          </select>
          <select
            name="mode"
            value={filters.mode}
            onChange={handleFilterChange}
            className="w-full p-2 border rounded-lg"
          >
            <option value="">Select Mode</option>
            <option value="Online">Online</option>
            <option value="Offline">Offline</option>
          </select>
        </div>
      </div>

      {/* Display Projects */}
      <div className="w-full max-w-3xl mt-6 bg-white p-6 rounded-lg shadow-md">
        <h3 className="text-xl font-bold mb-4">Available Projects</h3>
        <ul>
          {filteredProjects.map((project) => (
            <li key={project._id} className="border-b py-4">
              <h4 className="font-semibold">{project.title}</h4>
              <p>{project.description}</p>
              <p><strong>Skills:</strong> {project.skills}</p>
              <p><strong>Level:</strong> {project.level}</p>
              <p><strong>Duration:</strong> {project.duration}</p>
              <p><strong>Mode:</strong> {project.mode}</p>
              <button
                onClick={() => handleConnect(project._id, { name: "User", message: "I want to join!" })}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg mt-2"
              >
                Connect with this project
              </button>
            </li>
          ))}
        </ul>
      </div>

      {/* Project Form */}
      {isFormVisible && (
        <form
          onSubmit={handleSubmit}
          className="w-full max-w-3xl bg-white p-6 mt-4 rounded-lg shadow-lg"
        >
          <div className="mb-4">
            <label className="block text-gray-700 font-semibold">Project Title</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              required
              className="w-full p-2 border rounded-lg focus:border-blue-500"
              placeholder="Enter project title"
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 font-semibold">Description</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              required
              className="w-full p-2 border rounded-lg focus:border-blue-500"
              placeholder="Briefly describe your project"
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 font-semibold">Prerequisites</label>
            <input
              type="text"
              name="prerequisites"
              value={formData.prerequisites}
              onChange={handleChange}
              required
              className="w-full p-2 border rounded-lg focus:border-blue-500"
              placeholder="Any required knowledge before joining?"
            />
          </div>

          <div className="mb-4">
            <label className="block text-gray-700 font-semibold">Required Skills</label>
            <input
              type="text"
              name="skills"
              value={formData.skills}
              onChange={handleChange}
              required
              className="w-full p-2 border rounded-lg focus:border-blue-500"
              placeholder="E.g., React, Python, Data Science"
            />
          </div>

          <button
            type="submit"
            className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
          >
            Submit Project
          </button>
        </form>
      )}
    </div>
  );
};

export default ProjectPage;
